import{_ as a,o as n,c as o,a3 as t}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"79. Meal Allowance","description":"","frontmatter":{"title":"79. Meal Allowance","eba":"Mental Health Services 2024-2028","topics":["hours","overtime","shift-work","allowances"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/allowances/79-meal-allowance.md","filePath":"ebas/mental-health/rpn-pen-mho/allowances/79-meal-allowance.md"}'),l={name:"ebas/mental-health/rpn-pen-mho/allowances/79-meal-allowance.md"};function r(s,e,i,c,h,p){return n(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="_79-meal-allowance" tabindex="-1">79. Meal Allowance <a class="header-anchor" href="#_79-meal-allowance" aria-label="Permalink to &quot;79. Meal Allowance&quot;">​</a></h1><p><strong>79.1</strong> Meal where overtime worked beyond one hour An Employee who works overtime will in the circumstances described in sub-clause 79.2 receive either:</p><p><strong>(a)</strong> where an Employer has its own cooking and dining facilities, an adequate meal; or</p><p><strong>(b)</strong> the relevant meal allowance as set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>79.2</strong> Qualification for meal or payment The entitlement under subclause 79.1 arises where in addition to a shift an Employee is required to work more than:</p><p><strong>(a)</strong> one hour beyond the usual finishing hour of work (Monday to Sunday inclusive) in which case the relevant allowance is ‘Allowance A’; or</p><p><strong>(b)</strong> five hours beyond usual finishing hour of work (Monday to Sunday inclusive) in which case the relevant allowances are ‘Allowance A’ and ‘Allowance B’.</p><p><strong>79.3</strong> Qualification for meal or payment on a rostered day off The entitlement under subclause 79.1 arises where, on a rostered day off, an Employee is required to work more than:</p><p><strong>(a)</strong> five hours overtime, in which case the relevant allowance is ’Allowance A’; or</p><p><strong>(b)</strong> nine hours overtime, in which case the relevant allowances are ‘Allowance A’ and ‘Allowance B’.</p><p><strong>79.4</strong> Where provision does not apply The allowance described at subclauses 79.2 and 79.3 above is not payable where the Employee:</p><p><strong>(a)</strong> receives an adequate meal as described at subclause 79.1(a); or</p><p><strong>(b)</strong> could reasonably return home for a meal within the period allowed.</p><p><strong>79.5</strong> Same day payment On request the meal allowance shall be paid on the same day as overtime is worked where practicable.</p><p><strong>79.6</strong> Payments are in addition The payment of a meal allowance under this clause is in addition to any overtime payment.</p>',15)])])}const w=a(l,[["render",r]]);export{m as __pageData,w as default};
